n, m = map(int, input().split())
a = list(map(int, input().split()))
b = list(map(int, input().split()))

dp = [[-1] * (1000001) for _ in range(n + 1)]
dp[0][0] = 0

for i in range(1, n + 1):
    for j in range(1000001):
        if dp[i - 1][j] != -1:
            if i in b:
                dp[i][j] = max(dp[i - 1][j], dp[i - 1][j + a[i - 1]] + j)
            else:
                dp[i][j] = max(dp[i - 1][j], dp[i - 1][j + a[i - 1]] + j - a[i - 1])

print(max(dp[n]))
